---@class LFightIdleArea
local LFightIdleArea = LxClass("LFightIdleArea",nil)

function LFightIdleArea:LFightIdleArea()
	self._areaId = 0
	self._areaRef = nil

	self._boardDpList = {}

	self._boardNameList = nil

	self._boardDataMap = {}

	self._offsetX = 0
	self._offsetY = 0

	self._index = 0

	self._bInitDp = false

	self._bCircle = false -- true 循环地图时候 上下边 为了不穿帮增加的 区域

	self._shadowBoardMap = {}

	self._pos = Vector3.zero
end

function LFightIdleArea:Create(index,areaRef,boards,boardsRoot)
	self._index = index
	self._areaRef = areaRef
	self._areaId = areaRef.areaId
	self._pos = areaRef.pos:Clone()

	self._boards = boards
	self._boardsRoot = boardsRoot

	local boardList = areaRef.boardList
	self._boardNameList = boardList

	local boardDataMap = {}
	self._boardDataMap = boardDataMap

	local shadowMap = {}
	self._shadowBoardMap = shadowMap

	for k,v in ipairs(boardList) do
		local ref = boards[v]
		boardDataMap[v] = ref
		if not string.isempty(ref.shadow) then
			shadowMap[ref.shadow] = v
		end
	end
end

function LFightIdleArea:GetAreaPos()
	return self._pos
end

function LFightIdleArea:SetRange(min,max)
	self._min = min
	self._max = max
end

function LFightIdleArea:GetRange()
	return self._min, self._max
end

function LFightIdleArea:GetAreaId()
	return self._areaId
end

function LFightIdleArea:GetAreaIndex()
	return self._index
end

function LFightIdleArea:GetBoardNameList()
	return self._boardNameList
end

function LFightIdleArea:GetShadowBoardMap()
	return self._shadowBoardMap
end

function LFightIdleArea:SetCircle(bCircle)
	self._bCircle = bCircle
end

function LFightIdleArea:SetOffSet(offsetX,offsetY)
	self._offsetX = offsetX
	self._offsetY = offsetY
end

function LFightIdleArea:IsInitDp()
	return self._bInitDp
end

function LFightIdleArea:ConvertBoardName(boardName)
	--if(self._bCircle) then return "show_"..boardName end
	return boardName
end

function LFightIdleArea:ConvertAreaDpName()
	return "Area"..tostring(self._areaId)
end

function LFightIdleArea:InitDp()
	if self._bInitDp then return end
	self._bInitDp = true
	local boardDpList = self._boardDpList
	local boardNameList = self._boardNameList
	local boardDataMap = self._boardDataMap
	local offsetX = self._offsetX
	local offsetY = self._offsetY

	local boardRootTrans = self._boardsRoot
	local areaTrans = CS.FindTrans(boardRootTrans,self:ConvertAreaDpName())
	if not areaTrans then return end

	for _k,v in ipairs(boardNameList) do
		local boardTrans = CS.FindTrans(areaTrans,v)
		if(boardTrans) then
			local gameObj = boardTrans.gameObject
			local collider = CS.FindTrans(boardTrans,"collider")
			if collider then
				CS.ShowObject(collider.gameObject,false)
			end
			table.insert(boardDpList,{name=keyName,dp=gameObj,collider=collider})
		end
	end
end

function LFightIdleArea:EnableAreaPress(bEnable)
	local boardDpList = self._boardDpList or {}
	for k,v in ipairs(boardDpList) do
		local collider = v.collider
		if collider then
			CS.ShowObject(collider.gameObject,bEnable)
		end
	end
end

function LFightIdleArea:ClearDp()
	if(not self._bInitDp) then return end
	self._bInitDp = false
	local boardDpList = self._boardDpList
	self._boardDpList = {}
	for k,v in ipairs(boardDpList) do
		local collider = v.collider
		if collider then
			CS.ShowObject(collider.gameObject,false)
		end
	end
end

function LFightIdleArea:Destroy()
	table.removeall(self)
end

return  LFightIdleArea